        ETMAddNORAD_CAT_ID(builder, self.NORAD_CAT_ID)
        if self.OBJECT_NAME is not None:
            ETMAddOBJECT_NAME(builder, OBJECT_NAME)
        if self.OBJECT_ID is not None:
            ETMAddOBJECT_ID(builder, OBJECT_ID)
        if self.CAT_OBJECT_NAME is not None:
            ETMAddCAT_OBJECT_NAME(builder, CAT_OBJECT_NAME)
        if self.CAT_OBJECT_ID is not None:
            ETMAddCAT_OBJECT_ID(builder, CAT_OBJECT_ID)
        if self.FACILITY_TYPE is not None:
            ETMAddFACILITY_TYPE(builder, FACILITY_TYPE)
        if self.SEARCH_TEXT is not None:
            ETMAddSEARCH_TEXT(builder, SEARCH_TEXT)
        if self.OWNER is not None:
            ETMAddOWNER(builder, OWNER)
        if self.STATUS_CODE is not None:
            ETMAddSTATUS_CODE(builder, STATUS_CODE)
        if self.LAUNCH_DATE is not None:
            ETMAddLAUNCH_DATE(builder, LAUNCH_DATE)
        if self.LAUNCH_YEAR is not None:
            ETMAddLAUNCH_YEAR(builder, LAUNCH_YEAR)
        if self.ORBIT_REGIME is not None:
            ETMAddORBIT_REGIME(builder, ORBIT_REGIME)
        ETMAddPERIOD(builder, self.PERIOD)
        ETMAddINCLINATION(builder, self.INCLINATION)
        ETMAddAPOGEE(builder, self.APOGEE)
        ETMAddPERIGEE(builder, self.PERIGEE)
        ETMAddMEAN_MOTION(builder, self.MEAN_MOTION)
        ETMAddECCENTRICITY(builder, self.ECCENTRICITY)
        ETMAddBSTAR(builder, self.BSTAR)
        ETMAddHAS_GP(builder, self.HAS_GP)
        if self.RESERVED is not None:
            ETMAddRESERVED(builder, RESERVED)
        ETM = ETMEnd(builder)
        return ETM
